public class OverrideBug {
    static class Base {
        void greet(String name) { System.out.println("Hello, " + name); }
    }
    static class Sub extends Base {
        void greet(String name, String title) {   // overload, not override
            System.out.println("Hello, " + title + " " + name);
        }
    }
    public static void main(String[] args) {
        Base b = new Sub();
        b.greet("Alice");   // calls Base.greet, not Sub.greet
    }
}
